1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	type Customer = { yearsWithMHPCO: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 0.1;
9	const LOYALTY_DISCOUNT = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
12	const CURSE_SURCHARGE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const COMPONENT_BLOCK_SIZE = 3;
16	const COMPONENT_BLOCK_PRICE = 60;
17	
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
30	
31	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
32	
33	const priceForComponentGroup = (type: string, count: number): number =>
34	  count === COMPONENT_BLOCK_SIZE
35	    ? COMPONENT_BLOCK_PRICE
36	    : count * BASE_PREMIUM_BY_TYPE[type];
37	
38	const countByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  }
43	  return counts;
44	};
45	
46	const sumBasePremiumsFor = (items: Item[]): number => {
47	  const mainItemsTotal = items
48	    .filter((item) => !isComponent(item))
49	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
50	
51	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
52	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
53	
54	  return mainItemsTotal + componentsTotal;
55	};
56	
57	// Item surcharges: each rule adds a percentage of the item's base premium when it applies.
58	const ITEM_SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
59	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
60	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE },
61	];
62	
63	const surchargeRateFor = (item: Item): number =>
64	  ITEM_SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
65	
66	const itemSurchargesFor = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + basePremiumOf(item) * surchargeRateFor(item), 0);
68	
69	type PolicyContext = { customer: Customer; quoteIndex: number };
70	
71	// Policy modifiers: each rule applies a +/- percentage of the policy base when its predicate holds.
72	const POLICY_MODIFIER_RULES: { applies: (ctx: PolicyContext) => boolean; rate: number }[] = [
73	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
74	  { applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD, rate: -LOYALTY_DISCOUNT },
75	  { applies: (ctx) => ctx.quoteIndex > 0, rate: -FOLLOWUP_CONTRACT_DISCOUNT },
76	];
77	
78	const policyModifierRateFor = (ctx: PolicyContext): number =>
79	  POLICY_MODIFIER_RULES.reduce((rate, rule) => rate + (rule.applies(ctx) ? rule.rate : 0), 0);
80	
81	const computePremium = (items: Item[], ctx: PolicyContext): number => {
82	  const policyBase = sumBasePremiumsFor(items);
83	  const itemSurcharges = itemSurchargesFor(items);
84	  const policyModifiers = policyBase * policyModifierRateFor(ctx);
85	  return policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE;
86	};
87	
88	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
89	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
90	const roundUpToGold = (amount: number): number =>
91	  Math.ceil(Math.round(amount * 1e6) / 1e6);
92	
93	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
94	  let quoteIndex = 0;
95	  const results = scenario.steps.map((step) => {
96	    const ctx: PolicyContext = { customer: scenario.customer, quoteIndex };
97	    quoteIndex += 1;
98	    return { premium: roundUpToGold(computePremium(step.items, ctx)) };
99	  });
100	  return { results };
101	};
